import{_ as e,o as t,c as s,j as a,a as o,a1 as i}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"遮覆炽天七重圆环（Rho Aias）","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/4.B级/遮覆炽天七重圆环（Rho Aias）.md","filePath":"4.资源分区/7.物品与装备/3.防具/4.B级/遮覆炽天七重圆环（Rho Aias）.md"}'),p={name:"4.资源分区/7.物品与装备/3.防具/4.B级/遮覆炽天七重圆环（Rho Aias）.md"};function h(n,r,_,d,l,b){return t(),s("div",null,[...r[0]||(r[0]=[a("h1",{id:"遮覆炽天七重圆环-rho-aias",tabindex:"-1"},[o("遮覆炽天七重圆环（Rho Aias） "),a("a",{class:"header-anchor",href:"#遮覆炽天七重圆环-rho-aias","aria-label":'Permalink to "遮覆炽天七重圆环（Rho Aias）"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调011")])])],-1),i('<h1 id="遮覆炽天七重圆环-rho-aias-1" tabindex="-1">遮覆炽天七重圆环（Rho Aias） <a class="header-anchor" href="#遮覆炽天七重圆环-rho-aias-1" aria-label="Permalink to &quot;遮覆炽天七重圆环（Rho Aias）&quot;">​</a></h1><p>遮覆炽天七重圆环（Rho Aias）<br> 魔幻本质<br> 价格：B+2000<br> 结界宝具</p><p>概念武装-盾牌</p><p>原典为古希腊英雄，大埃阿斯所持有的，蒙覆七层牛皮的青铜盾牌。大埃阿斯以此盾牌抵挡住了赫克托尔那洞穿一切的投枪。此后，该事迹升华为了防御性能极其强大的结界宝具。<br> 该宝具展开后的形态为一个核心环绕着七朵璀璨花瓣的圆形盾状结界。</p><p>类别：盾牌<br> 体积：2-10</p><p>展开方式：持有者空置一只可正常使用的手臂，将五指伸展并念出宝具名称——【Rho Aias】，宝具便会在手掌的面向方位展开。这是一个自由动作。收回宝具同样。</p><p>宝具需要持有者每轮都支付1至5点魔力维持展开，宝具的体积为当轮为此支付的魔力数*2。</p><p>当宝具展开时，持有者获得如下效果：</p><p>1、持有者在进行格挡时，可以以【专注技能+意志专业等级】代替【武技技能+白刃相关专业等级】进行相关数值计算（即在没有其他资源影响情况下，在你格挡后，直到你的下次行动开始前，你在防御上获得相当于你的【专注技能+意志专业等级】/2的格挡加值）。<br> 2、宝具具有【格挡X】特性，X的值等同于持有者的决心值。<br> 3、当持有者使用该宝具格挡来自展开方向外侧的攻击时，持有者会为宝具展开方向的内侧【宝具体积*6】米半径的扇形范围内、除自己以外的所有单位（无论敌我）提供全遮蔽。<br> 4、宝具展开后，完整状态下拥有环绕核心的7片花瓣。在应对攻击时，以一个自由动作，持有者可选择将完好的每一片花瓣视为2点临时生命来抵消伤害。花瓣作为临时生命使用以后将碎裂且无法再次使用，直到你进行一次长休息后，所有碎裂的花瓣才会重置为完好如初的状态并可以再度使用。<br> 5、持有者在应对一次攻击时，可以一个自由动作支付一定的意志力以抵消等额的伤害，支付意志力的上限为当前宝具周围存留的完好花瓣数（所有花瓣完好时为7）。但如果持有者一次支付了等同于上限的意志力，则宝具周围展开的花瓣自动会碎裂1片。<br> 6、每日一次，仅在尚有完好的花瓣时才能使用，以一个自由动作使用，持有者可将一次足以对自身造成致死性危机的远程攻击的伤害减少一半，这是A级命运来源的无敌效果；或者持有者免疫一次由投掷武器所发出的远程攻击带来的S级及以下的即死效果。<br> 本能力触发以后，宝具周围展开的花瓣将会全数自动碎裂。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const R=e(p,[["render",h]]);export{A as __pageData,R as default};
